const prisma = new PrismaClient({ datasources: { db: { url: process.env.POSTGRES_PRISMA_URL }}});

async function getMetrics(start, end) {
  try {
    if (start && end) {
      const metrics = await prisma.dailyPerformance.findMany({
        where: {
          date: {
            gte: new Date(start),
            lte: new Date(end)
          }
        }
      });

      if (metrics.length === 0) return null;

      return {
        date: end,
        receitaGerada: metrics.reduce((acc, m) => acc + m.receitaGerada, 0),
        vendas: metrics.reduce((acc, m) => acc + m.vendas, 0),
        ticketMedio: metrics.reduce((acc, m) => acc + m.receitaGerada, 0) / (metrics.reduce((acc, m) => acc + m.vendas, 0) || 1)
      };
    }
    return null;
  } catch (error) {
    console.error(''Error fetching metrics:'', error);
    return null;
  }
}

async function testDashboard() {
  console.log(''🧪 Testando função getMetrics do dashboard...'');

  const metrics = await getMetrics(''2026-03-09'', ''2026-03-09'');

